import{_ as t,a,b as o,c as r,d as n}from"./chunks/复制刷新令牌.IwW3dosg.js";import{_ as i,o as d,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Přidání kanálu OneDrive","description":"","frontmatter":{},"headers":[],"relativePath":"cs-CZ/upload/onedrive.md","filePath":"cs-CZ/upload/onedrive.md","lastUpdated":1781962217000}'),c={name:"cs-CZ/upload/onedrive.md"};function p(h,e,k,u,v,b){return d(),l("div",null,[...e[0]||(e[0]=[s('<h1 id="pridani-kanalu-onedrive" tabindex="-1">Přidání kanálu OneDrive <a class="header-anchor" href="#pridani-kanalu-onedrive" aria-label="Permalink to &quot;Přidání kanálu OneDrive&quot;">​</a></h1><h2 id="co-potrebujete-pred-zacatkem" tabindex="-1">Co potřebujete před začátkem <a class="header-anchor" href="#co-potrebujete-pred-zacatkem" aria-label="Permalink to &quot;Co potřebujete před začátkem&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Požadavek</th><th>Proč je potřeba</th></tr></thead><tbody><tr><td>Účet Microsoft</td><td>Pro přístup k administračním stránkám Microsoft a autorizaci OneDrive</td></tr><tr><td>Vaše doména ImgBed</td><td>Pro OAuth callback URL</td></tr><tr><td>Registrace aplikace</td><td>Pro vytvoření <code>Client ID</code> a <code>Client Secret</code></td></tr><tr><td>Účet OneDrive</td><td>Skutečné úložiště pro soubory</td></tr></tbody></table><h2 id="nastaveni" tabindex="-1">Nastavení <a class="header-anchor" href="#nastaveni" aria-label="Permalink to &quot;Nastavení&quot;">​</a></h2><h3 id="krok-1-otevrete-microsoft-entra-id" tabindex="-1">Krok 1: Otevřete Microsoft Entra ID <a class="header-anchor" href="#krok-1-otevrete-microsoft-entra-id" aria-label="Permalink to &quot;Krok 1: Otevřete Microsoft Entra ID&quot;">​</a></h3><ol><li>Otevřete <code>portal.azure.com</code>.</li><li>Nahoře vyhledejte <code>Microsoft Entra ID</code>.</li><li>Pokud se cílová stránka nezobrazí v nabídce, zvolte:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Continue searching in Microsoft Entra ID</span></span></code></pre></div><ol start="4"><li>Otevřete <code>Microsoft Entra ID</code>.</li><li>Otevřete <code>App registrations</code>.</li><li>Klikněte na <code>New registration</code>.</li></ol><h3 id="krok-2-zaregistrujte-aplikaci" tabindex="-1">Krok 2: Zaregistrujte aplikaci <a class="header-anchor" href="#krok-2-zaregistrujte-aplikaci" aria-label="Permalink to &quot;Krok 2: Zaregistrujte aplikaci&quot;">​</a></h3><p>Na stránce <code>New registration</code> vyplňte:</p><table tabindex="0"><thead><tr><th>Pole</th><th>Co zadat</th></tr></thead><tbody><tr><td>Name</td><td>Srozumitelný název, například <code>imgbed-onedrive</code></td></tr><tr><td>Supported account types</td><td>Vyberte podle tabulky níže</td></tr><tr><td>Redirect URI type</td><td><code>Web</code></td></tr><tr><td>Redirect URI</td><td><code>https://your-domain.com/api/oauth/onedrive/callback</code></td></tr></tbody></table><p>Doporučení pro typ účtu:</p><table tabindex="0"><thead><tr><th>Váš scénář</th><th>Supported Account Types</th></tr></thead><tbody><tr><td>Jen osobní OneDrive</td><td>Zvolte možnost pro osobní účty Microsoft.</td></tr><tr><td>Osobní i pracovní/školní účty</td><td>Zvolte možnost podporující osobní i organizační účty.</td></tr><tr><td>Jen firemní nebo školní OneDrive</td><td>Zvolte možnost pro organizační účty.</td></tr></tbody></table><p>Po vyplnění formuláře klikněte na registraci.</p><p><img src="'+t+'" alt="Vytvoření aplikace OneDrive" loading="lazy"></p><h3 id="krok-3-zkopirujte-udaje-aplikace" tabindex="-1">Krok 3: Zkopírujte údaje aplikace <a class="header-anchor" href="#krok-3-zkopirujte-udaje-aplikace" aria-label="Permalink to &quot;Krok 3: Zkopírujte údaje aplikace&quot;">​</a></h3><p>Po vytvoření aplikace zkopírujte z přehledu tyto hodnoty:</p><table tabindex="0"><thead><tr><th>Pole Microsoft</th><th>Pole ImgBed</th></tr></thead><tbody><tr><td><code>Application (client) ID</code></td><td><code>Client ID</code></td></tr><tr><td><code>Directory (tenant) ID</code></td><td><code>Tenant ID</code> pro organizační účty</td></tr></tbody></table><p><img src="'+a+'" alt="Application ID a Tenant ID" loading="lazy"></p><h3 id="krok-4-vytvorte-client-secret" tabindex="-1">Krok 4: Vytvořte Client Secret <a class="header-anchor" href="#krok-4-vytvorte-client-secret" aria-label="Permalink to &quot;Krok 4: Vytvořte Client Secret&quot;">​</a></h3><ol><li>Otevřete <code>Certificates &amp; secrets</code>.</li><li>Klikněte na <code>New client secret</code>.</li><li>Zadejte libovolný, ale poznatelný popis.</li><li>Zvolte dobu platnosti.</li><li>Hodnotu <code>Value</code> zkopírujte hned po vytvoření.</li></ol><p><img src="'+o+'" alt="Uložení hodnoty Client Secret" loading="lazy"></p><h3 id="krok-5-pridejte-api-opravneni" tabindex="-1">Krok 5: Přidejte API oprávnění <a class="header-anchor" href="#krok-5-pridejte-api-opravneni" aria-label="Permalink to &quot;Krok 5: Přidejte API oprávnění&quot;">​</a></h3><ol><li>Otevřete <code>API permissions</code>.</li><li>Klikněte na <code>Add a permission</code>.</li><li>Vyberte <code>Microsoft Graph</code>.</li><li>Vyberte <code>Delegated permissions</code>.</li><li>Přidejte tato oprávnění:</li></ol><table tabindex="0"><thead><tr><th>Oprávnění</th><th>Účel</th></tr></thead><tbody><tr><td><code>Files.ReadWrite.All</code></td><td>Nahrávání souborů, vytváření složek a mazání souborů</td></tr><tr><td><code>offline_access</code></td><td>Umožní ImgBed získat <code>Refresh Token</code></td></tr><tr><td><code>User.Read</code></td><td>Čte informace o účtu a kapacitě</td></tr></tbody></table><h3 id="krok-6-vyplnte-kanal-onedrive" tabindex="-1">Krok 6: Vyplňte kanál OneDrive <a class="header-anchor" href="#krok-6-vyplnte-kanal-onedrive" aria-label="Permalink to &quot;Krok 6: Vyplňte kanál OneDrive&quot;">​</a></h3><p>V Nastavení nahrávání zvolte <code>OneDrive</code> a vyplňte:</p><table tabindex="0"><thead><tr><th>Pole ImgBed</th><th>Co zadat</th></tr></thead><tbody><tr><td>Název kanálu</td><td>Srozumitelný název, například <code>Main OneDrive</code></td></tr><tr><td>Client ID</td><td>Microsoft <code>Application (client) ID</code></td></tr><tr><td>Client Secret</td><td>Zkopírovaná hodnota <code>Client Secret Value</code></td></tr><tr><td>Tenant ID</td><td>Použijte tabulku níže</td></tr><tr><td>Refresh Token</td><td>Zatím nechte prázdné</td></tr><tr><td>Kořenový adresář</td><td>Volitelné. Výchozí je <code>imgbed</code>.</td></tr><tr><td>Poznámka</td><td>Volitelné</td></tr></tbody></table><p><img src="'+r+'" alt="Konfigurace kanálu OneDrive" loading="lazy"></p><p>Jak vyplnit <code>Tenant ID</code>:</p><table tabindex="0"><thead><tr><th>Zvolený typ účtu</th><th>ImgBed <code>Tenant ID</code></th></tr></thead><tbody><tr><td>Osobní účty</td><td><code>consumers</code></td></tr><tr><td>Osobní a organizační účty</td><td><code>common</code></td></tr><tr><td>Jen aktuální organizace</td><td><code>Directory (tenant) ID</code></td></tr></tbody></table><h3 id="krok-7-ziskejte-refresh-token" tabindex="-1">Krok 7: Získejte Refresh Token <a class="header-anchor" href="#krok-7-ziskejte-refresh-token" aria-label="Permalink to &quot;Krok 7: Získejte Refresh Token&quot;">​</a></h3><ol><li>V ImgBed klikněte na <code>Get Token</code>.</li><li>Přihlaste se k účtu Microsoft, který chcete připojit.</li><li>Potvrďte autorizaci.</li><li>Callback stránka zobrazí <code>Refresh Token</code>.</li><li>Zkopírujte ho.</li><li>Vraťte se do ImgBed a vložte ho do pole <code>Refresh Token</code>.</li></ol><p><img src="'+n+`" alt="Kopírování Refresh Token" loading="lazy"></p><h3 id="krok-8-ulozte-kanal" tabindex="-1">Krok 8: Uložte kanál <a class="header-anchor" href="#krok-8-ulozte-kanal" aria-label="Permalink to &quot;Krok 8: Uložte kanál&quot;">​</a></h3><p>Po vyplnění všech polí kanál uložte.</p><h2 id="rychly-postup" tabindex="-1">Rychlý postup <a class="header-anchor" href="#rychly-postup" aria-label="Permalink to &quot;Rychlý postup&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Otevřete portal.azure.com</span></span>
<span class="line"><span>-&gt; Vyhledejte Microsoft Entra ID</span></span>
<span class="line"><span>-&gt; Otevřete App registrations</span></span>
<span class="line"><span>-&gt; Zaregistrujte novou aplikaci</span></span>
<span class="line"><span>-&gt; Vyplňte Name / Supported account types / Web redirect URI</span></span>
<span class="line"><span>-&gt; Zaregistrujte</span></span>
<span class="line"><span>-&gt; Zkopírujte Application (client) ID</span></span>
<span class="line"><span>-&gt; Zkontrolujte callback URL v Authentication</span></span>
<span class="line"><span>-&gt; Vytvořte Client Secret v Certificates &amp; secrets</span></span>
<span class="line"><span>-&gt; Přidejte oprávnění v API permissions</span></span>
<span class="line"><span>-&gt; Zadejte Client ID / Client Secret / Tenant ID do ImgBed</span></span>
<span class="line"><span>-&gt; Klikněte Get Token</span></span>
<span class="line"><span>-&gt; Zkopírujte Refresh Token z callback stránky</span></span>
<span class="line"><span>-&gt; Vložte ho do ImgBed a uložte</span></span></code></pre></div><h2 id="reference" tabindex="-1">Reference <a class="header-anchor" href="#reference" aria-label="Permalink to &quot;Reference&quot;">​</a></h2><ol><li>Registrace aplikace Microsoft Entra: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/quickstart-register-app</a></li><li>Microsoft identity platform authorization code flow: <a href="https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/entra/identity-platform/v2-oauth2-auth-code-flow</a></li><li>Microsoft Graph user authentication: <a href="https://learn.microsoft.com/en-us/graph/auth-v2-user" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/graph/auth-v2-user</a></li></ol>`,40)])])}const g=i(c,[["render",p]]);export{y as __pageData,g as default};
